import psycopg2
from flask import Flask, request, jsonify

app = Flask(__name__)

@app.route('/extensions', methods=['POST'])
def create_extension():
    extension_name = request.form['extension_name']
    conn = psycopg2.connect(
        host="localhost",
        database="mydatabase",
        user="myuser",
        password="mypassword"
    )
    cur = conn.cursor()
    cur.execute("CREATE EXTENSION {}".format(extension_name))
    conn.commit()
    cur.close()
    return jsonify({'status': 'success', 'message': 'Extension created successfully'})

@app.route('/extensions/<extension_name>', methods=['DELETE'])
def drop_extension(extension_name):
    conn = psycopg2.connect(
        host="localhost",
        database="mydatabase",
        user="myuser",
        password="mypassword"
    )
    cur = conn.cursor()
    cur.execute("DROP EXTENSION {}".format(extension_name))
    conn.commit()
    cur.close()
    return jsonify({'status': 'success', 'message': 'Extension dropped successfully'})

@app.route('/extensions/<extension_name>', methods=['GET'])
def get_extension(extension_name):
    conn = psycopg2.connect(
        host="localhost",
        database="mydatabase",
        user="myuser",
        password="mypassword"
    )
    cur = conn.cursor()
    cur.execute("SELECT * FROM pg_extension WHERE extname = %s", (extension_name,))
    result = cur.fetchone()
    if result is None:
        return jsonify({'status': 'error', 'message': 'Extension not found'})
    else:
        return jsonify({'status': 'success', 'message': 'Extension found', 'data': result})

